proof_block:
// Pin the target endpoint (same value in both post-states because both ensures
// keep get_thread(thread_ptr).endpoint_descriptors equal to pre_self_'s).
let target_endpoint =
    pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// === Proc equality ===
// The ensures-foralls for proc each carry the trigger
// `postX_self_.get_proc(p_ptr)`. Re-asserting both inside an `assert forall`
// goal whose own trigger explicitly mentions both `get_proc` calls forces z3
// to instantiate the two ensures-foralls at the same witness.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) == post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// === Container equality ===
// Same trigger-alignment pattern; the ensures triggers are
// `postX_self_.get_container(container_ptr)`.
assert forall|container_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(container_ptr), post2_self_.get_container(container_ptr)]
    pre_self_.container_dom().contains(container_ptr) implies
    post1_self_.get_container(container_ptr) == post2_self_.get_container(container_ptr) by {
    assert(post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr));
    assert(post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr));
}

// === Thread equality (non-target) ===
// Both ensures-foralls for the thread case share trigger
// `pre_self_.get_thread(t_ptr)`; a single mention in the goal lines them up.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr implies
    post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// === Endpoint domain agreement (used as the contains-guard for the next forall) ===
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());

// === Endpoint equality (non-target) ===
// Triggers in the ensures are `postX_self_.get_endpoint(e_ptr)`.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_endpoint implies
    post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr) by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

// === Target thread fields are pinned by ensures ===
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= post2_self_.get_thread(thread_ptr).ipc_payload);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);

// === Target endpoint fields are pinned by ensures ===
assert(post1_self_.get_endpoint(target_endpoint).queue_state
    == post2_self_.get_endpoint(target_endpoint).queue_state);
assert(post1_self_.get_endpoint(target_endpoint).owning_threads
    == post2_self_.get_endpoint(target_endpoint).owning_threads);
assert(post1_self_.get_endpoint(target_endpoint).queue@
    == post2_self_.get_endpoint(target_endpoint).queue@);

// === Domain and page_closure equalities ===
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// === Map extensional equality, per perms field ===
// Process perms: same dom; pointwise equality via spec_get_proc inlining of
// `&self.process_perms@[p_ptr].value()`, which means our get_proc equality
// gives `process_perms@[k].value() == process_perms@[k].value()`. With
// process_perms_wf both maps' entries are init and have addr == k, so they
// agree on every observable; ext_equal then closes the map.
assert((post1_self_.process_perms)@.dom() =~= (post2_self_.process_perms)@.dom()) by {
    assert((post1_self_.process_perms)@.dom() == pre_self_.proc_dom());
    assert((post2_self_.process_perms)@.dom() == pre_self_.proc_dom());
}
assert forall|p_ptr: ProcPtr|
    #![trigger (post1_self_.process_perms)@[p_ptr], (post2_self_.process_perms)@[p_ptr]]
    (post1_self_.process_perms)@.dom().contains(p_ptr) implies
    (post1_self_.process_perms)@[p_ptr] == (post2_self_.process_perms)@[p_ptr] by {
    assert(pre_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) == post2_self_.get_proc(p_ptr));
}
assert((post1_self_.process_perms)@ =~= (post2_self_.process_perms)@);

// Container perms.
assert((post1_self_.container_perms)@.dom() =~= (post2_self_.container_perms)@.dom()) by {
    assert((post1_self_.container_perms)@.dom() == pre_self_.container_dom());
    assert((post2_self_.container_perms)@.dom() == pre_self_.container_dom());
}
assert forall|c_ptr: ContainerPtr|
    #![trigger (post1_self_.container_perms)@[c_ptr], (post2_self_.container_perms)@[c_ptr]]
    (post1_self_.container_perms)@.dom().contains(c_ptr) implies
    (post1_self_.container_perms)@[c_ptr] == (post2_self_.container_perms)@[c_ptr] by {
    assert(pre_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_container(c_ptr) == post2_self_.get_container(c_ptr));
}
assert((post1_self_.container_perms)@ =~= (post2_self_.container_perms)@);

// Thread perms.
assert((post1_self_.thread_perms)@.dom() =~= (post2_self_.thread_perms)@.dom()) by {
    assert((post1_self_.thread_perms)@.dom() == pre_self_.thread_dom());
    assert((post2_self_.thread_perms)@.dom() == pre_self_.thread_dom());
}
assert forall|t_ptr: ThreadPtr|
    #![trigger (post1_self_.thread_perms)@[t_ptr], (post2_self_.thread_perms)@[t_ptr]]
    (post1_self_.thread_perms)@.dom().contains(t_ptr) implies
    (post1_self_.thread_perms)@[t_ptr] == (post2_self_.thread_perms)@[t_ptr] by {
    assert(pre_self_.thread_dom().contains(t_ptr));
    if t_ptr == thread_ptr {
        assert(post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr));
    } else {
        assert(post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr));
    }
}
assert((post1_self_.thread_perms)@ =~= (post2_self_.thread_perms)@);

// Endpoint perms.
assert((post1_self_.endpoint_perms)@.dom() =~= (post2_self_.endpoint_perms)@.dom()) by {
    assert((post1_self_.endpoint_perms)@.dom() == pre_self_.endpoint_dom());
    assert((post2_self_.endpoint_perms)@.dom() == pre_self_.endpoint_dom());
}
assert forall|e_ptr: EndpointPtr|
    #![trigger (post1_self_.endpoint_perms)@[e_ptr], (post2_self_.endpoint_perms)@[e_ptr]]
    (post1_self_.endpoint_perms)@.dom().contains(e_ptr) implies
    (post1_self_.endpoint_perms)@[e_ptr] == (post2_self_.endpoint_perms)@[e_ptr] by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    if e_ptr == target_endpoint {
        assert(post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr));
    } else {
        assert(post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr));
    }
}
assert((post1_self_.endpoint_perms)@ =~= (post2_self_.endpoint_perms)@);
